import novamind_api as nm

# Check daily spending breakdown
r = nm.query("SELECT day, category, amount FROM ledger WHERE day >= 70 ORDER BY day, category")
daily = {}
for row in r['rows']:
    d = row['day']
    cat = row['category']
    amt = row['amount']
    if d not in daily:
        daily[d] = {}
    if cat not in daily[d]:
        daily[d][cat] = 0
    daily[d][cat] += amt

for d in sorted(daily.keys()):
    print(f"\nDay {d}:")
    for cat in sorted(daily[d].keys()):
        print(f"  {cat}: ${daily[d][cat]:.2f}")
    net = sum(daily[d].values())
    print(f"  NET: ${net:.2f}")
